TOWN_GROUPS = {"East": ["March Ridge", "Muldraugh", "West Point", "Valley Station", "Louisville", "Misc"], "West": ["Irvington", "Ekron", "Brandenburg", "Echo Creek", "Riverside", "Fallas Lake", "Rosewood"]}

def lcg_rand(seed, index):
    a = 1664525
    c = 1013904223
    m = 2**32
    state = seed
    for _ in range(index):
        state = (a * state + c) % m
    return state / m

def clamp_index(idx, pool_length):
    return max(0, min(idx, pool_length - 1))

def group_by_town(region):
    towns = []
    by_name = {}
    region_towns = TOWN_GROUPS[region]
    for loc in LOCATIONS:
        if not loc['town'] or loc['town'] == 'Hardcore':
            continue
        if loc['town'] not in region_towns:
            continue
        if loc['town'] not in by_name:
            by_name[loc['town']] = {'town': loc['town'], 'locs': []}
            towns.append(by_name[loc['town']])
        by_name[loc['town']]['locs'].append(loc)
    return towns

def compute_challenges():
    now = datetime.now(timezone.utc)
    date_str = now.strftime('%Y%m%d')
    seed = int(date_str)

    kill_idx = clamp_index(int(lcg_rand(seed, 1 * 13) * len(POOL_KILL)), len(POOL_KILL))
    eat_idx = clamp_index(int(lcg_rand(seed, 4 * 13) * len(POOL_EATDRINK)), len(POOL_EATDRINK))
    fish_idx = clamp_index(int(lcg_rand(seed, 5 * 13) * len(POOL_FISHHUNT)), len(POOL_FISHHUNT))
    craft_idx = clamp_index(int(lcg_rand(seed, 6 * 13) * len(POOL_CRAFTBUILD)), len(POOL_CRAFTBUILD))
    misc_idx = clamp_index(int(lcg_rand(seed, 7 * 13) * len(POOL_MISC)), len(POOL_MISC))

    kill_challenge = POOL_KILL[kill_idx]
    eat_challenge = POOL_EATDRINK[eat_idx]
    fish_challenge = POOL_FISHHUNT[fish_idx]
    craft_challenge = POOL_CRAFTBUILD[craft_idx]
    misc_challenge = POOL_MISC[misc_idx]

    east_towns = group_by_town('East')
    west_towns = group_by_town('West')

    east_town = east_towns[seed % len(east_towns)]
    west_town = west_towns[(seed + 7) % len(west_towns)]
    east_loc = east_town['locs'][seed % len(east_town['locs'])]
    west_loc = west_town['locs'][(seed + 3) % len(west_town['locs'])]

    exclude_towns = {east_loc['town'], west_loc['town']}

    visit_locs = [l for l in LOCATIONS if l['town'] and l['town'] != 'Hardcore' and l['town'] not in exclude_towns]
    visit_idx = clamp_index(int(lcg_rand(seed, 4 * 13) * len(visit_locs)), len(visit_locs))
    visit_loc = visit_locs[visit_idx]

    quest_exclude = exclude_towns | {visit_loc['town']}
    quest_locs = [l for l in LOCATIONS if l['town'] and l['town'] != 'Hardcore' and l['town'] not in quest_exclude]
    quest_loc_idx = clamp_index(int(lcg_rand(seed, 3 * 13) * len(quest_locs)), len(quest_locs))
    quest_loc = quest_locs[quest_loc_idx]

    quest_item_idx = clamp_index(int(lcg_rand(seed, 3 * 17) * len(QUEST_ITEMS)), len(QUEST_ITEMS))
    quest_item = QUEST_ITEMS[quest_item_idx]

    visit_npc_idx = clamp_index(int(seed * 100) % len(NPC_NAMES), len(NPC_NAMES))
    visit_npc = NPC_NAMES[visit_npc_idx]

    quest_npc_idx = visit_npc_idx
    while quest_npc_idx == visit_npc_idx:
        quest_npc_idx = clamp_index(int((seed + 0.5) * 100) % len(NPC_NAMES), len(NPC_NAMES))
    quest_npc = NPC_NAMES[quest_npc_idx]

    challenges = [
        {"title": kill_challenge["title"]},
        {"title": f"Deposit {quest_item['itemName']} in to the Safe at {quest_loc['name']}"},
        {"title": f"Find Barney the Gnome at {visit_loc['name']}"},
        {"title": eat_challenge["title"]},
        {"title": fish_challenge["title"]},
        {"title": craft_challenge["title"]},
        {"title": misc_challenge["title"]},
    ]

    return challenges, date_str

def post_challenges(challenges, date_str):
    day = int(date_str[6:8])
    month_names = [
        "January", "February", "March", "April", "May", "June",
        "July", "August", "September", "October", "November", "December"
    ]
    month = month_names[int(date_str[4:6]) - 1]
    year = date_str[:4]
    suffix = "th"
    if day in (1, 21, 31):
        suffix = "st"
    elif day in (2, 22):
        suffix = "nd"
    elif day in (3, 23):
        suffix = "rd"
    date_formatted = f"{day}{suffix} {month} {year}"

    challenge_lines = []
    for ch in challenges:
        challenge_lines.append(ch['title'])

    challenges_text = "\n".join(challenge_lines)

    if WEBHOOK_URL == "YOUR_WEBHOOK_URL_HERE":
        print("[WARNING] WEBHOOK_URL not set. Printing challenges to console:")
        print(f"\n  Daily Challenges - {date_formatted}")
        print("  " + "=" * 35)
        for ch in challenges:
            print(f"  {ch['title']}")
            print("  " + "-" * 35)
        print("\n  Website Information")
        print("  Data mirrors in-game challenge selection.")
        print("  All times UTC.\n")
        return None

    html_path = WEBSITE_DIR / "index.html"
    screenshot_path = WEBSITE_DIR / "bot" / "temp_screenshot.png"

    try:
        with sync_playwright() as p:
            browser = p.chromium.launch(headless=True)
            page = browser.new_page(viewport={"width": 400, "height": 800})
            page.goto(f"file:///{html_path.resolve()}")
            page.wait_for_timeout(2000)
            panel = page.locator(".panel")
            footer = page.locator(".panel-footer")
            panel_box = panel.bounding_box()
            footer_box = footer.bounding_box()
            clip = {
                "x": panel_box["x"],
                "y": panel_box["y"],
                "width": panel_box["width"],
                "height": footer_box["y"] - panel_box["y"]
            }
            page.screenshot(path=str(screenshot_path), clip=clip)
            browser.close()

        with open(screenshot_path, "rb") as f:
            image_bytes = f.read()

        files = {"file": ("daily_challenges.png", image_bytes, "image/png")}
        response = requests.post(WEBHOOK_URL, files=files)

        if screenshot_path.exists():
            screenshot_path.unlink()

        return response.status_code
    except Exception as e:
        print(f"Screenshot error: {e}")
        payload = {"content": f"**Daily Challenges - {date_formatted}**\n\n{challenges_text}"}
        response = requests.post(WEBHOOK_URL, json=payload)
        return response.status_code

def daily_job():
    try:
        challenges, date_str = compute_challenges()
        status = post_challenges(challenges, date_str)
        if status:
            print(f"[{datetime.now(timezone.utc).isoformat()}] Posted challenges (HTTP {status})")
        else:
            print(f"[{datetime.now(timezone.utc).isoformat()}] Challenges computed (no webhook)")
    except Exception as e:
        print(f"[{datetime.now(timezone.utc).isoformat()}] Error: {e}")

if __name__ == "__main__":
    import sys
    
    print("Daily Challenges Bot starting...")
    if WEBHOOK_URL != "YOUR_WEBHOOK_URL_HERE":
        print(f"Webhook URL: {WEBHOOK_URL[:30]}...")
    else:
        print("Webhook URL: NOT SET (will print to console)")

    if "--post-now" in sys.argv:
        daily_job()
        sys.exit(0)

    daily_job()

    schedule.every().day.at("00:00").do(daily_job)
    print("Scheduled daily job at 00:00 UTC. Press Ctrl+C to stop.")

    while True:
        schedule.run_pending()
        time.sleep(60)
